function calculateCost(atlasCost, selfHostedCost) {
  if (atlasCost < selfHostedCost) {
    return "MongoDB Atlas is cheaper.";
  } else if (selfHostedCost < atlasCost) {
    return "Self-hosted is cheaper.";
  } else {
    return "Both options have the same cost.";
  }
}

