codeExercises.solution:
function chooseSolution(projectRequirements) {
  const { requiresCustomization, hasDBA, isLargeScale } = projectRequirements;

  if (requiresCustomization || (hasDBA && isLargeScale)) {
    return 'Self-hosted';
  } else {
    return 'Atlas';
  }
}

const project1 = { requiresCustomization: true, hasDBA: true, isLargeScale: true };
const project2 = { requiresCustomization: false, hasDBA: false, isLargeScale: false };

console.log(`Project 1 recommendation: ${chooseSolution(project1)}`);
console.log(`Project 2 recommendation: ${chooseSolution(project2)}`);
